const LoadingScreen = ({ isVisible }) => {
  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          initial={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 1.2 }}
          className="fixed inset-0 bg-black z-50 flex items-center justify-center overflow-hidden"
        >
          <div className="relative w-full h-full flex flex-col items-center justify-center">
            {/* Animated grid background */}
            <div className="absolute inset-0 opacity-20">
              <div className="absolute inset-0" style={{
                backgroundImage: 'linear-gradient(0deg, transparent 24%, rgba(0,255,200,.05) 25%, rgba(0,255,200,.05) 26%, transparent 27%, transparent 74%, rgba(0,255,200,.05) 75%, rgba(0,255,200,.05) 76%, transparent 77%, transparent), linear-gradient(90deg, transparent 24%, rgba(0,255,200,.05) 25%, rgba(0,255,200,.05) 26%, transparent 27%, transparent 74%, rgba(0,255,200,.05) 75%, rgba(0,255,200,.05) 76%, transparent 77%, transparent)',
                backgroundSize: '50px 50px'
              }} />
            </div>

            {/* Centered content */}
            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 0.8 }}
              className="relative z-10 text-center"
            >
              <motion.div
                animate={{ rotate: 360 }}
                transition={{ duration: 3, repeat: Infinity, ease: 'linear' }}
                className="mb-8 flex justify-center"
              >
                <div className="w-16 h-16 rounded-lg border-2 border-cyan-500 border-t-transparent border-r-transparent" />
              </motion.div>

              <motion.h2
                initial={{ y: 20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ delay: 0.3, duration: 0.8 }}
                className="text-2xl font-bold text-cyan-400 mb-4 font-mono tracking-wider"
              >
                INITIALIZING SECURE SYSTEM
              </motion.h2>

              <motion.div
                initial={{ width: 0 }}
                animate={{ width: '200px' }}
                transition={{ duration: 2, ease: 'easeInOut' }}
                className="h-1 bg-gradient-to-r from-cyan-500 via-purple-500 to-transparent mx-auto mb-4"
              />

              <motion.p
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.5, duration: 0.8 }}
                className="text-cyan-300/60 text-sm font-mono"
              >
                Loading cybersecurity profile...
              </motion.p>
            </motion.div>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

const NavBar = () => {
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <motion.nav
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.8 }}
      className={`fixed top-0 left-0 right-0 z-40 px-6 lg:px-12 py-4 transition-all duration-300 ${
        isScrolled ? 'bg-black/80 backdrop-blur-md border-b border-cyan-500/20' : 'bg-transparent'
      }`}
    >
      <div className="max-w-7xl mx-auto flex items-center justify-between">
        <motion.div
          whileHover={{ scale: 1.05 }}
          className="text-xl font-bold bg-gradient-to-r from-cyan-400 to-purple-500 bg-clip-text text-transparent font-mono tracking-wider"
        >
          SJ.CYBER
        </motion.div>

        <div className="hidden md:flex items-center gap-8">
          {['About', 'Projects', 'Skills', 'Timeline', 'Contact'].map((item) => (
            <motion.a
              key={item}
              href={`#${item.toLowerCase()}`}
              whileHover={{ color: '#00ffcc' }}
              className="text-sm text-cyan-300/70 hover:text-cyan-400 transition-colors font-mono"
            >
              {item}
            </motion.a>
          ))}
        </div>

        <motion.div
          whileHover={{ scale: 1.1 }}
          className="w-8 h-8 rounded border border-cyan-500 flex items-center justify-center cursor-pointer"
        >
          <Shield size={16} className="text-cyan-400" />
        </motion.div>
      </div>
    </motion.nav>
  );
};

const HeroSection = () => {
  const containerRef = useRef(null);
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const handleMouseMove = (e) => {
      if (containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        setMousePosition({
          x: (e.clientX - rect.left) / rect.width,
          y: (e.clientY - rect.top) / rect.height,
        });
      }
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  return (
    <section
      ref={containerRef}
      className="relative min-h-screen flex items-center justify-center overflow-hidden pt-20"
    >
      {/* Animated background */}
      <div className="absolute inset-0">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-cyan-600/20 rounded-full filter blur-3xl opacity-20 animate-pulse" />
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-purple-600/20 rounded-full filter blur-3xl opacity-20 animate-pulse delay-700" />
      </div>

      {/* Grid overlay */}
      <div
        className="absolute inset-0 opacity-10"
        style={{
          backgroundImage: 'linear-gradient(0deg, transparent 24%, rgba(0,255,200,.1) 25%, rgba(0,255,200,.1) 26%, transparent 27%, transparent 74%, rgba(0,255,200,.1) 75%, rgba(0,255,200,.1) 76%, transparent 77%, transparent), linear-gradient(90deg, transparent 24%, rgba(0,255,200,.1) 25%, rgba(0,255,200,.1) 26%, transparent 27%, transparent 74%, rgba(0,255,200,.1) 75%, rgba(0,255,200,.1) 76%, transparent 77%, transparent)',
          backgroundSize: '100px 100px'
        }}
      />

      <div className="relative z-10 max-w-4xl mx-auto px-6 text-center">
        {/* Animated title */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1, delay: 0.2 }}
        >
          <motion.p
            className="text-cyan-400 font-mono text-sm mb-4 tracking-widest"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4 }}
          >
            // WELCOME TO MY DIGITAL FORTRESS
          </motion.p>

          <h1 className="text-5xl md:text-7xl font-black mb-6 font-mono tracking-tight">
            <motion.span
              initial={{ opacity: 0, x: -50 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.5, duration: 0.8 }}
              className="block text-white"
            >
              Sabahat
            </motion.span>
            <motion.span
              initial={{ opacity: 0, x: 50 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.6, duration: 0.8 }}
              className="block bg-gradient-to-r from-cyan-400 via-purple-500 to-cyan-400 bg-clip-text text-transparent"
            >
              Jahangir
            </motion.span>
          </h1>
        </motion.div>

        {/* Subtitle with typing effect */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.8, duration: 0.8 }}
          className="mb-8"
        >
          <p className="text-xl md:text-2xl text-cyan-300/80 font-mono mb-2">
            Cybersecurity Enthusiast | Future Digital Forensics Officer
          </p>
          <p className="text-sm md:text-base text-purple-300/60 font-mono">
            BS Computer Science @ FAST NUCES | Graduating June 2026
          </p>
        </motion.div>

        {/* Call to action */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 1.2, duration: 0.8 }}
          className="flex flex-wrap gap-4 justify-center mb-12"
        >
          <motion.a
            href="#projects"
            whileHover={{ scale: 1.05, boxShadow: '0 0 30px rgba(0,255,200,0.3)' }}
            whileTap={{ scale: 0.95 }}
            className="px-8 py-3 bg-cyan-500/20 border border-cyan-500 text-cyan-400 rounded-lg font-mono text-sm hover:bg-cyan-500/30 transition-all"
          >
            Explore Projects
          </motion.a>
          <motion.a
            href="#contact"
            whileHover={{ scale: 1.05, boxShadow: '0 0 30px rgba(168,85,247,0.3)' }}
            whileTap={{ scale: 0.95 }}
            className="px-8 py-3 bg-purple-500/20 border border-purple-500 text-purple-400 rounded-lg font-mono text-sm hover:bg-purple-500/30 transition-all"
          >
            Get in Touch
          </motion.a>
        </motion.div>

        {/* Scroll indicator */}
        <motion.div
          animate={{ y: [0, 10, 0] }}
          transition={{ duration: 2, repeat: Infinity }}
          className="flex justify-center mt-12"
        >
          <ChevronDown className="text-cyan-400 w-6 h-6" />
        </motion.div>
      </div>
    </section>
  );
};

