const ProjectCard = ({ project, index }) => {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.1 }}
      viewport={{ once: true }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="group relative"
    >
      <div className="absolute -inset-1 bg-gradient-to-r from-cyan-600 to-purple-600 rounded-xl opacity-0 group-hover:opacity-20 blur transition duration-500" />

      <div className="relative bg-gradient-to-br from-slate-900 to-black border border-cyan-500/30 rounded-xl p-8 hover:border-cyan-500/60 transition-all duration-500">
        {/* Project icon */}
        <motion.div
          animate={{ rotate: isHovered ? 12 : 0 }}
          transition={{ duration: 0.3 }}
          className="mb-4 inline-block"
        >
          {project.icon}
        </motion.div>

        <h3 className="text-2xl font-bold text-white mb-3 font-mono">{project.title}</h3>

        <p className="text-cyan-300/70 text-sm mb-6 font-mono leading-relaxed">{project.description}</p>

        <motion.div
          animate={{ x: isHovered ? 5 : 0 }}
          transition={{ duration: 0.3 }}
          className="space-y-3 mb-6"
        >
          {project.features.map((feature, i) => (
            <div key={i} className="flex items-center gap-2 text-cyan-300/60 text-xs font-mono">
              <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full" />
              <span>{feature}</span>
            </div>
          ))}
        </motion.div>

        <div className="flex flex-wrap gap-2">
          {project.tech.map((tech, i) => (
            <motion.span
              key={i}
              whileHover={{ scale: 1.05, boxShadow: '0 0 15px rgba(0,255,200,0.5)' }}
              className="px-3 py-1 bg-cyan-500/10 border border-cyan-500/30 text-cyan-300 text-xs rounded font-mono hover:bg-cyan-500/20 transition-all cursor-pointer"
            >
              {tech}
            </motion.span>
          ))}
        </div>

        {project.status && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.2 }}
            className="mt-4 px-3 py-1 bg-purple-500/20 border border-purple-500/30 text-purple-300 text-xs rounded font-mono inline-block"
          >
            {project.status}
          </motion.div>
        )}
      </div>
    </motion.div>
  );
};

